<?php $vis=count(array_filter($productos,fn($p)=>!empty($p['visible'])));$occ=count($productos)-$vis;$sinFoto=count(array_filter($productos,fn($p)=>empty($p['portada'])));$porCat=[]; foreach($productos as $p){foreach(($p['categorias']?:['Sin categoría']) as $c)$porCat[$c]=($porCat[$c]??0)+1;} arsort($porCat); $max=max($porCat?:[1]); $sinPrecio=array_filter($productos,fn($p)=>(float)($p['precio']??$p['precio_venta']??0)<=0); $ocultos=array_filter($productos,fn($p)=>empty($p['visible'])); ?>
<section class="page-head"><h1>Estadísticas</h1><p>Resumen general del sistema y salud del catálogo.</p></section><div class="kpi-grid"><div class="kpi"><span>Total productos</span><strong><?= count($productos) ?></strong></div><div class="kpi"><span>Visibles</span><strong><?= $vis ?></strong></div><div class="kpi"><span>Ocultos</span><strong><?= $occ ?></strong></div><div class="kpi"><span>Sin foto</span><strong><?= $sinFoto ?></strong></div></div>
<div class="chart-panel"><div class="panel"><h2>Productos por categoría</h2><?php foreach($porCat as $cat=>$count): ?><div class="bar-row"><span><?= e($cat) ?></span><div><i style="width:<?= max(5,($count/$max)*100) ?>%"></i></div><strong><?= $count ?></strong></div><?php endforeach; ?></div><div class="panel"><h2>Alertas del catálogo</h2><div class="stat-list"><div class="stat-line"><span>Productos sin precio</span><strong><?= count($sinPrecio) ?></strong></div><div class="stat-line"><span>Productos ocultos</span><strong><?= count($ocultos) ?></strong></div><div class="stat-line"><span>Categorías cargadas</span><strong><?= count($categorias) ?></strong></div></div></div></div>
